$content = Get-Content -Path 'app\src\main\java\hcmute\edu\vn\mytasklist\MainActivity.java' -Raw
$content = $content -replace 'taskViewModel\.delete\(task\.getId\(\)\);', 'taskViewModel.delete(task);'
$content = $content -replace 'cal\.setTime\(task\.getDueDate\(\)\);', 'cal.setTime(new Date(task.getDueDate()));'
$content = $content -replace '(?s)private List<TaskEntity> getFilteredTasks\(\) \{.*?return taskDao\.getByCategory\(currentFilter\);\s*\}\s*\}', 'private List<TaskEntity> getFilteredTasks() { List<TaskEntity> result = new ArrayList<>(); if (allTasks == null) return result; Date todayStart = getDayStart(new Date()); Calendar c = Calendar.getInstance(); c.add(Calendar.DAY_OF_YEAR, 1); Date tomorrowStart = getDayStart(c.getTime()); Calendar c7 = Calendar.getInstance(); c7.add(Calendar.DAY_OF_YEAR, 7); Date nextWeekStart = getDayStart(c7.getTime()); for (TaskEntity t : allTasks) { boolean include = false; if ("Today".equals(currentFilter)) { if (t.getDueDate() != null && getDayStart(new Date(t.getDueDate())).equals(todayStart)) include = true; } else if ("Next 7 Days".equals(currentFilter)) { if (t.getDueDate() != null && !getDayStart(new Date(t.getDueDate())).before(todayStart) && getDayStart(new Date(t.getDueDate())).before(nextWeekStart)) include = true; } else if ("Completed".equals(currentFilter)) { if (t.isCompleted()) include = true; } else { if (currentFilter.equals(t.getCategory())) include = true; } if (include) result.add(t); } return result; }'
Set-Content -Path 'app\src\main\java\hcmute\edu\vn\mytasklist\MainActivity.java' -Value $content
